{"content":"import { World, PanelUI, Follower, ScreenSpace, THREE } from '@iwsdk/core';
import { BowlingSystem } from './game-system';

async function main() {
  const container = document.getElementById('app')!;

  const world = await World.create(container, {
    xr: { offer: 'once' },
    browserControls: true,
    features: {
      physics: false,
      locomotion: false,
      grabbing: false,
    },
  });

  // Camera setup for bowling view
  world.camera.position.set(0, 2.0, 1.5);
  world.camera.lookAt(0, 0, -6);

  // Panel configs
  const panels: { config: string; type: 'world' | 'hud' | 'screen' ; pos?: [number, number, number]; scale?: number }[] = [
    { config: './ui/title.json', type: 'world', pos: [0, 2.2, -4], scale: 3.0 },
    { config: './ui/modeselect.json', type: 'world', pos: [0, 2.2, -4], scale: 3.0 },
    { config: './ui/hud.json', type: 'hud' },
    { config: './ui/scorecard.json', type: 'world', pos: [1.8, 1.8, -3], scale: 2.0 },
    { config: './ui/powerbar.json', type: 'hud' },
    { config: './ui/gameover.json', type: 'world', pos: [0, 2.2, -4], scale: 3.0 },
    { config: './ui/pause.json', type: 'world', pos: [0, 2.2, -3], scale: 3.0 },
    { config: './ui/leaderboard.json', type: 'world', pos: [0, 2.2, -4], scale: 3.0 },
    { config: './ui/achievements.json', type: 'world', pos: [0, 2.2, -4], scale: 3.0 },
    { config: './ui/settings.json', type: 'world', pos: [0, 2.2, -4], scale: 3.0 },
    { config: './ui/help.json', type: 'world', pos: [0, 2.2, -4], scale: 3.0 },
    { config: './ui/ballselect.json', type: 'world', pos: [0, 2.2, -4], scale: 3.0 },
    { config: './ui/stats.json', type: 'world', pos: [0, 2.2, -4], scale: 3.0 },
    { config: './ui/toast.json', type: 'hud' },
    { config: './ui/countdown.json', type: 'hud' },
  ];

  for (const p of panels) {
    const entity = world.ecs.create();
    world.ecs.addComponent(entity, PanelUI, { config: p.config });

    if (p.type === 'hud') {
      world.ecs.addComponent(entity, Follower, { target: world.player.head, distance: 1.5 });
    } else if (p.type === 'world') {
      const obj = new THREE.Object3D();
      if (p.pos) obj.position.set(p.pos[0], p.pos[1], p.pos[2]);
      if (p.scale) obj.scale.setScalar(p.scale);
      world.scene.add(obj);
      entity.object3D = obj;
    }
  }

  world.registerSystem(BowlingSystem);
}

main().catch(console.error);
